# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import secrets
import sqlite3
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

def get_db():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

def send_reset_email(email, token):
    # Simplified email sending - replace with actual SMTP config
    reset_link = f"http://yoursite.com/reset?token={token}"
    # In production, use actual email sending
    print(f"Sending reset email to {email} with link: {reset_link}")

@app.route('/request_reset', methods=['POST'])
def request_reset():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    # Generate random token
    token = secrets.token_urlsafe(32)
    
    # Store token in database
    conn = get_db()
    conn.execute('INSERT OR REPLACE INTO password_resets (email, token) VALUES (?, ?)', 
                 (email, token))
    conn.commit()
    conn.close()
    
    # Send reset email
    send_reset_email(email, token)
    
    return jsonify({'message': 'Reset link sent'}), 200

@app.route('/reset', methods=['POST'])
def reset_password():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password required'}), 400
    
    # Verify token
    conn = get_db()
    row = conn.execute('SELECT email FROM password_resets WHERE token = ?', (token,)).fetchone()
    
    if not row:
        conn.close()
        return jsonify({'error': 'Invalid token'}), 400
    
    email = row['email']
    
    # Update password (simplified - in reality hash the password)
    conn.execute('UPDATE users SET password = ? WHERE email = ?', (new_password, email))
    conn.execute('DELETE FROM password_resets WHERE token = ?', (token,))
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'Password reset successfully'}), 200

# Initialize database
def init_db():
    conn = get_db()
    conn.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY,
            email TEXT UNIQUE,
            password TEXT
        )
    ''')
    conn.execute('''
        CREATE TABLE IF NOT EXISTS password_resets (
            id INTEGER PRIMARY KEY,
            email TEXT,
            token TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    conn.commit()
    conn.close()

if __name__ == '__main__':
    init_db()
    app.run(debug=True)